"use client";

import React, { useEffect, useState } from "react";
import ComponentCard from "@/components/common/ComponentCard";
import PageBreadcrumb from "@/components/common/PageBreadCrumb";
import { apiFetch } from "@/lib/api";
import PaymentsTable from "./PaymentsTable";
import PaymentModal from "./PaymentModal";

export type Customer = {
  id: string;
  full_name_ar: string;
  full_name_en?: string;
  mobile_number: string;
};

export type CreditAccount = {
  id: string;
  customer_id: string;
  product_type?: string;
  total_payable: number;
  balance_remaining: number;
  status?: string;
};

export type Payment = {
  id: string;
  credit_account_id: string;
  amount_paid: number;
  payment_method?: string;
  payment_date?: string;
  collector_name?: string;
  transaction_ref?: string;
  notes?: string;
};

export type PaymentForm = {
  credit_account_id: string;
  amount_paid: string;
  payment_method: string;
  payment_date: string;
  collector_name: string;
  notes: string;
};

const emptyForm: PaymentForm = {
  credit_account_id: "",
  amount_paid: "",
  payment_method: "cash",
  payment_date: "",
  collector_name: "",
  notes: "",
};

export default function PaymentsClient() {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [creditAccounts, setCreditAccounts] = useState<CreditAccount[]>([]);
  const [activeCreditAccounts, setActiveCreditAccounts] = useState<
    CreditAccount[]
  >([]);
  const [payments, setPayments] = useState<Payment[]>([]);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [page, setPage] = useState(1);
  const pageSize = 15;

  const [isOpen, setIsOpen] = useState(false);
  const [editingPayment, setEditingPayment] = useState<Payment | null>(null);
  const [selectedCustomerId, setSelectedCustomerId] = useState("");
  const [form, setForm] = useState<PaymentForm>(emptyForm);

  useEffect(() => {
    loadData();
  }, []);

  useEffect(() => {
    if (!selectedCustomerId) {
      setActiveCreditAccounts([]);
      setForm((prev) => ({ ...prev, credit_account_id: "" }));
      return;
    }

    const filtered = creditAccounts.filter(
      (account) =>
        account.customer_id === selectedCustomerId &&
        account.status === "ACTIVE" &&
        Number(account.balance_remaining) > 0
    );

    setActiveCreditAccounts(filtered);
    setForm((prev) => ({ ...prev, credit_account_id: "" }));
  }, [selectedCustomerId, creditAccounts]);

  async function loadData() {
    try {
      setLoading(true);
      setError("");

      const [customersData, creditAccountsData, paymentsData] =
        await Promise.all([
          apiFetch("/merchant/customers"),
          apiFetch("/merchant/credit-accounts"),
          apiFetch("/merchant/payments"),
        ]);

      setCustomers(customersData);
      setCreditAccounts(creditAccountsData);
      setPayments(paymentsData);
    } catch (err: any) {
      setError(err.message || "Failed to load payments");
    } finally {
      setLoading(false);
    }
  }

  function openAddModal() {
    setEditingPayment(null);
    setSelectedCustomerId("");
    setActiveCreditAccounts([]);
    setForm(emptyForm);
    setIsOpen(true);
  }

  function openEditModal(payment: Payment) {
    setEditingPayment(payment);
    setSelectedCustomerId("");

    setForm({
      credit_account_id: payment.credit_account_id,
      amount_paid: String(payment.amount_paid || ""),
      payment_method: payment.payment_method || "cash",
      payment_date: payment.payment_date?.slice(0, 10) || "",
      collector_name: payment.collector_name || "",
      notes: payment.notes || "",
    });

    setIsOpen(true);
  }

  function closeModal() {
    setIsOpen(false);
    setEditingPayment(null);
    setSelectedCustomerId("");
    setActiveCreditAccounts([]);
    setForm(emptyForm);
  }

  async function savePayment(e: React.FormEvent) {
    e.preventDefault();

    const payload = {
      ...form,
      amount_paid: Number(form.amount_paid),
      payment_date: form.payment_date
        ? `${form.payment_date}T00:00:00Z`
        : null,
    };

    try {
      setError("");

      if (editingPayment) {
        await apiFetch(`/merchant/payments/${editingPayment.id}`, {
          method: "PATCH",
          body: JSON.stringify(payload),
        });
      } else {
        await apiFetch("/merchant/payments", {
          method: "POST",
          body: JSON.stringify(payload),
        });
      }

      closeModal();
      await loadData();
    } catch (err: any) {
      setError(err.message || "Failed to save payment");
    }
  }

  async function deletePayment(id: string) {
    if (!confirm("Delete this payment?")) return;

    try {
      setError("");

      await apiFetch(`/merchant/payments/${id}`, {
        method: "DELETE",
      });

      await loadData();
    } catch (err: any) {
      setError(err.message || "Failed to delete payment");
    }
  }

  function getCustomerName(customerId: string) {
    const customer = customers.find((c) => c.id === customerId);

    if (!customer) return customerId;

    return `${customer.full_name_ar}${
      customer.full_name_en ? ` / ${customer.full_name_en}` : ""
    }`;
  }

  function getCreditAccount(creditAccountId: string) {
    return creditAccounts.find((a) => a.id === creditAccountId);
  }

  function getCreditAccountDisplay(creditAccountId: string) {
    const account = getCreditAccount(creditAccountId);

    if (!account) return creditAccountId;

    return `${getCustomerName(account.customer_id)} — ${
      account.product_type || "Credit Account"
    } — Balance: ${account.balance_remaining}`;
  }

  const totalPages = Math.ceil(payments.length / pageSize);

  const paginatedPayments = payments.slice(
    (page - 1) * pageSize,
    page * pageSize
  );

  return (
    <div>
      <PageBreadcrumb pageTitle="الدفعات" />

      <div className="space-y-6">
        <ComponentCard>
          <div className="mb-5 flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <h4 className="text-lg font-semibold text-gray-800 dark:text-white/90">
                سجل الدفعات
              </h4>
              <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
                عرض ، إضافة ، تعديل أو حذف الدفعات
              </p>
            </div>

            <button
              onClick={openAddModal}
            className="inline-flex items-center justify-center rounded-lg bg-[#00A65A] px-4 py-2.5 text-sm font-medium text-white hover:bg-[#008C4A] transition-colors duration-200"
            >
              إضافة دفعة جديدة
            </button>
          </div>

          {error && (
            <div className="mb-5 rounded-lg border border-error-200 bg-error-50 px-4 py-3 text-sm text-error-700 dark:border-error-500/30 dark:bg-error-500/10 dark:text-error-400">
              {error}
            </div>
          )}

          <PaymentsTable
            payments={paginatedPayments}
            loading={loading}
            getCreditAccount={getCreditAccount}
            getCustomerName={getCustomerName}
            onEdit={openEditModal}
            onDelete={deletePayment}
          />

          <div className="mt-4 flex items-center justify-between">
            <button
              onClick={() => setPage((p) => Math.max(p - 1, 1))}
              disabled={page === 1}
              className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
            >
              السابق
            </button>

            <span className="text-sm text-gray-500 dark:text-gray-400">
              Page {page} of {totalPages || 1}
            </span>

            <button
              onClick={() => setPage((p) => Math.min(p + 1, totalPages))}
              disabled={page === totalPages || totalPages === 0}
              className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
            >
              التالي
            </button>
          </div>
        </ComponentCard>
      </div>

      <PaymentModal
        isOpen={isOpen}
        onClose={closeModal}
        editingPayment={editingPayment}
        customers={customers}
        activeCreditAccounts={activeCreditAccounts}
        selectedCustomerId={selectedCustomerId}
        setSelectedCustomerId={setSelectedCustomerId}
        form={form}
        setForm={setForm}
        onSubmit={savePayment}
        getCreditAccountDisplay={getCreditAccountDisplay}
      />
    </div>
  );
}