"use client";

import React from "react";
import { Modal } from "@/components/ui/modal";
import Input from "@/components/form/input/InputField";
import Label from "@/components/form/Label";
import type {
  CreditAccount,
  Customer,
  Payment,
  PaymentForm,
} from "./PaymentsClient";

type Props = {
  isOpen: boolean;
  onClose: () => void;
  editingPayment: Payment | null;
  customers: Customer[];
  activeCreditAccounts: CreditAccount[];
  selectedCustomerId: string;
  setSelectedCustomerId: React.Dispatch<React.SetStateAction<string>>;
  form: PaymentForm;
  setForm: React.Dispatch<React.SetStateAction<PaymentForm>>;
  onSubmit: (e: React.FormEvent) => void;
  getCreditAccountDisplay: (creditAccountId: string) => string;
};

const selectClass =
  "h-11 w-full rounded-lg border border-gray-300 bg-transparent px-4 py-2.5 text-sm text-gray-800 shadow-theme-xs focus:border-brand-300 focus:outline-hidden focus:ring-3 focus:ring-brand-500/10 dark:border-gray-700 dark:bg-gray-900 dark:text-white/90";

export default function PaymentModal({
  isOpen,
  onClose,
  editingPayment,
  customers,
  activeCreditAccounts,
  selectedCustomerId,
  setSelectedCustomerId,
  form,
  setForm,
  onSubmit,
  getCreditAccountDisplay,
}: Props) {
  return (
    <Modal isOpen={isOpen} onClose={onClose} className="max-w-[800px] m-4">
      <div className="no-scrollbar relative w-full max-w-[800px] overflow-y-auto rounded-3xl bg-white p-4 dark:bg-gray-900 lg:p-11">
        <div className="px-2 pr-14">
          <h4 className="mb-2 text-2xl font-semibold text-gray-800 dark:text-white/90">
            {editingPayment ? "Edit Payment" : "Add Payment"}
          </h4>

          <p className="mb-6 text-sm text-gray-500 dark:text-gray-400 lg:mb-7">
            Enter payment details below.
          </p>
        </div>

        <form
          key={editingPayment?.id || "new-payment"}
          onSubmit={onSubmit}
          className="flex flex-col"
        >
          <div className="custom-scrollbar max-h-[520px] overflow-y-auto px-2 pb-3">
            <h5 className="mb-5 text-lg font-medium text-gray-800 dark:text-white/90 lg:mb-6">
              Payment Information
            </h5>

            <div className="grid grid-cols-1 gap-x-6 gap-y-5 lg:grid-cols-2">
              {editingPayment ? (
                <div className="lg:col-span-2">
                  <Label>Credit Account</Label>
                  <Input
                    type="text"
                    value={getCreditAccountDisplay(form.credit_account_id)}
                    readOnly
                  />
                  <p className="mt-1 text-xs text-gray-500 dark:text-gray-400">
                    Credit account cannot be changed after payment creation.
                  </p>
                </div>
              ) : (
                <>
                  <div>
                    <Label>Customer</Label>
                    <select
                      className={selectClass}
                      value={selectedCustomerId}
                      onChange={(e) => setSelectedCustomerId(e.target.value)}
                      required
                    >
                      <option value="">Select customer</option>

                      {customers.map((customer) => (
                        <option key={customer.id} value={customer.id}>
                          {customer.full_name_ar}
                          {customer.full_name_en
                            ? ` / ${customer.full_name_en}`
                            : ""}{" "}
                          - {customer.mobile_number}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div>
                    <Label>Active Credit Account</Label>
                    <select
                      className={`${selectClass} ${
                        !selectedCustomerId
                          ? "cursor-not-allowed bg-gray-100 opacity-75 dark:bg-gray-800"
                          : ""
                      }`}
                      value={form.credit_account_id}
                      onChange={(e) =>
                        setForm({
                          ...form,
                          credit_account_id: e.target.value,
                        })
                      }
                      required
                      disabled={!selectedCustomerId}
                    >
                      <option value="">Select active credit account</option>

                      {activeCreditAccounts.map((account) => (
                        <option key={account.id} value={account.id}>
                          {account.product_type || "Credit Account"} - Balance:{" "}
                          {account.balance_remaining} - Total:{" "}
                          {account.total_payable}
                        </option>
                      ))}
                    </select>
                  </div>
                </>
              )}

              <div>
                <Label>Amount Paid</Label>
                <Input
                  type="number"
                  step="0.01"
                  defaultValue={form.amount_paid}
                  onChange={(e) =>
                    setForm({ ...form, amount_paid: e.target.value })
                  }
                  required
                />
              </div>

              <div>
                <Label>Payment Method</Label>
                <select
                  className={selectClass}
                  value={form.payment_method}
                  onChange={(e) =>
                    setForm({ ...form, payment_method: e.target.value })
                  }
                >
                  <option value="cash">Cash</option>
                  <option value="bank_transfer">Bank Transfer</option>
                  <option value="card">Card</option>
                  <option value="other">Other</option>
                </select>
              </div>

              <div>
                <Label>Payment Date</Label>
                <Input
                  type="date"
                  defaultValue={form.payment_date}
                  onChange={(e) =>
                    setForm({ ...form, payment_date: e.target.value })
                  }
                />
              </div>

              <div>
                <Label>Collector Name</Label>
                <Input
                  type="text"
                  defaultValue={form.collector_name}
                  onChange={(e) =>
                    setForm({ ...form, collector_name: e.target.value })
                  }
                />
              </div>

              <div className="lg:col-span-2">
                <Label>Notes</Label>
                <textarea
                  className="min-h-[120px] w-full rounded-lg border border-gray-300 bg-transparent px-4 py-3 text-sm text-gray-800 shadow-theme-xs placeholder:text-gray-400 focus:border-brand-300 focus:outline-hidden focus:ring-3 focus:ring-brand-500/10 dark:border-gray-700 dark:bg-gray-900 dark:text-white/90"
                  defaultValue={form.notes}
                  onChange={(e) =>
                    setForm({ ...form, notes: e.target.value })
                  }
                />
              </div>
            </div>
          </div>

          <div className="flex items-center gap-3 px-2 mt-6 lg:justify-end">
            <button
              type="button"
              onClick={onClose}
              className="rounded-lg border border-gray-300 px-4 py-2.5 text-sm font-medium text-gray-700 hover:bg-gray-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
            >
              Close
            </button>

            <button
              type="submit"
              className="rounded-lg bg-brand-500 px-4 py-2.5 text-sm font-medium text-white hover:bg-brand-600"
            >
              {editingPayment ? "Save Changes" : "Add Payment"}
            </button>
          </div>
        </form>
      </div>
    </Modal>
  );
}