"use client";

import React from "react";
import Badge from "@/components/ui/badge/Badge";
import {
  Table,
  TableBody,
  TableCell,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import type { CreditAccount, Payment } from "./PaymentsClient";

type Props = {
  payments: Payment[];
  loading: boolean;
  getCreditAccount: (creditAccountId: string) => CreditAccount | undefined;
  getCustomerName: (customerId: string) => string;
  onEdit: (payment: Payment) => void;
  onDelete: (id: string) => void;
};

export default function PaymentsTable({
  payments,
  loading,
  getCreditAccount,
  getCustomerName,
  onEdit,
  onDelete,
}: Props) {
  return (
    <div className="overflow-hidden rounded-xl border border-gray-200 bg-white dark:border-white/[0.05] dark:bg-white/[0.03]">
      <div className="max-w-full overflow-x-auto">
        <div>
          <Table>
            <TableHeader className="border-b border-gray-100 dark:border-white/[0.05]">
              <TableRow>
                {[
                  "الزبون / الحساب",
                  "المبلغ",
                  "طريقة الدفع",
                  "التاريخ",
                  "اسم الجابي",
                  "المرجع",
                  "-",
                ].map((header) => (
                  <TableCell
                    key={header}
                    isHeader
                    className="px-5 py-3 font-medium text-gray-500 text-start text-theme-xs dark:text-gray-400"
                  >
                    {header}
                  </TableCell>
                ))}
              </TableRow>
            </TableHeader>

            <TableBody className="divide-y divide-gray-100 dark:divide-white/[0.05]">
              {loading ? (
                <TableRow>
                  <TableCell className="px-5 py-6 text-center text-gray-500 text-theme-sm dark:text-gray-400">
                    Loading payments...
                  </TableCell>
                </TableRow>
              ) : payments.length === 0 ? (
                <TableRow>
                  <TableCell className="px-5 py-6 text-center text-gray-500 text-theme-sm dark:text-gray-400">
                    No payments found.
                  </TableCell>
                </TableRow>
              ) : (
                payments.map((payment) => {
                  const account = getCreditAccount(payment.credit_account_id);

                  return (
                    <TableRow key={payment.id}>
                      <TableCell className="px-5 py-4 sm:px-6 text-start">
                        <div>
                          <span className="block font-medium text-gray-800 text-theme-sm dark:text-white/90">
                            {account
                              ? getCustomerName(account.customer_id)
                              : payment.credit_account_id}
                          </span>

                          <span className="block text-gray-500 text-theme-xs dark:text-gray-400">
                            {account?.product_type || "Credit Account"}
                          </span>

                          <span className="block text-gray-400 text-theme-xs dark:text-gray-500">
                            Balance: {account?.balance_remaining ?? "-"}
                          </span>
                        </div>
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        {payment.amount_paid}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        <Badge size="sm" color="light">
                          {payment.payment_method || "unknown"}
                        </Badge>
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        {payment.payment_date
                          ? payment.payment_date.slice(0, 10)
                          : "-"}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        {payment.collector_name || "-"}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-start text-theme-sm dark:text-gray-400">
                        {payment.transaction_ref || "-"}
                      </TableCell>

                      <TableCell className="px-4 py-3 text-gray-500 text-theme-sm dark:text-gray-400">
                        <div className="flex items-center gap-2">
                          <button
                            type="button"
                            onClick={() => onEdit(payment)}
                            className="rounded-lg border border-gray-300 px-3 py-1.5 text-sm font-medium text-gray-700 hover:bg-gray-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
                          >
                            تعديل
                          </button>

                          <button
                            type="button"
                            onClick={() => onDelete(payment.id)}
                            className="rounded-lg bg-error-500 px-3 py-1.5 text-sm font-medium text-white hover:bg-error-600"
                          >
                            حذف
                          </button>
                        </div>
                      </TableCell>
                    </TableRow>
                  );
                })
              )}
            </TableBody>
          </Table>
        </div>
      </div>
    </div>
  );
}